$(document).ready((function(){AOS.init(),$("[data-bss-hover-animate]").mouseenter((function(){var t=$(this);t.addClass("animated "+t.attr("data-bss-hover-animate"))})).mouseleave((function(){var t=$(this);t.removeClass("animated "+t.attr("data-bss-hover-animate"))}))})),jQuery((function(t){t(window).on("scroll",(function(){(t(this).scrollTop()>=0||t(this).scrollTop()<=150)&&t(".navbar").addClass("fixed-top")}))})),$((function(){new Swiper(".swiper-container",{speed:1e3,pagination:".swiper-pagination",paginationClickable:!0,nextButton:".swiper-button-next",prevButton:".swiper-button-prev",autoplay:2e3,loop:!0})}));